class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def merge_two_sorted_lists(l1: ListNode, l2: ListNode) -> ListNode:
    dummy = ListNode()
    tail = dummy

    while l1 and l2:
        if l1.val < l2.val:
            tail.next = l1
            l1 = l1.next
        else:
            tail.next = l2
            l2 = l2.next
        tail = tail.next

    if l1:
        tail.next = l1
    elif l2:
        tail.next = l2

    return dummy.next

def merge_sort_linked_list(head: ListNode) -> ListNode:
    if not head or not head.next:
        return head

    # Find the middle of the list to split it into two halves
    prev_of_middle = None
    slow = head
    fast = head

    while fast and fast.next:
        prev_of_middle = slow
        slow = slow.next
        fast = fast.next.next

    # `slow` is now the head of the second half.
    # `prev_of_middle` is the last node of the first half.
    # Disconnect the two halves.
    if prev_of_middle:
        prev_of_middle.next = None

    first_half_head = head
    second_half_head = slow

    # Recursively sort the two halves
    sorted_first_half = merge_sort_linked_list(first_half_head)
    sorted_second_half = merge_sort_linked_list(second_half_head)

    # Merge the sorted halves
    return merge_two_sorted_lists(sorted_first_half, sorted_second_half)
